function sum(arr){
    let total = 0
    for(const value of arr){
        total += value
    }
    return total
}

// O(n) time, O(1) extra space

function hasZeroPair(arr){
    for(let i = 0; i < arr.length; i++){
        for(let j = i + 1; j < arr.length; j++){
            if(arr[i] + arr[j] === 0) return true
        }
    }
    return false
}

// O(n^2) time
